app = Flask(__name__)

REDIS_HOST = os.getenv("REDIS_HOST", "localhost")
REDIS_PORT = int(os.getenv("REDIS_PORT", "6379"))
REDIS_DB = int(os.getenv("REDIS_DB", "0"))
SESSION_TTL = int(os.getenv("SESSION_TTL", "3600"))
CACHE_TTL = int(os.getenv("CACHE_TTL", "300"))

redis_client = redis.Redis(
    host=REDIS_HOST,
    port=REDIS_PORT,
    db=REDIS_DB,
    decode_responses=True,
)

SESSION_COOKIE_NAME = "session_id"


def get_session_id():
    return request.cookies.get(SESSION_COOKIE_NAME)


def load_session(session_id):
    if not session_id:
        return {}
    data = redis_client.get(f"session:{session_id}")
    if not data:
        return {}
    try:
        return json.loads(data)
    except json.JSONDecodeError:
        return {}


def save_session(session_id, session_data):
    redis_client.set(f"session:{session_id}", json.dumps(session_data), ex=SESSION_TTL)


def session_required(view_func):
    @functools.wraps(view_func)
    def wrapper(*args, **kwargs):
        session_id = get_session_id()
        session_data = load_session(session_id)
        if not session_id or not session_data:
            session_id = str(uuid.uuid4())
            session_data = {"created_at": time.time()}
            save_session(session_id, session_data)
            response = make_response(view_func(*args, **kwargs))
            response.set_cookie(SESSION_COOKIE_NAME, session_id, max_age=SESSION_TTL, httponly=True, samesite="Lax")
            return response
        request.session_id = session_id
        request.session_data = session_data
        response = make_response(view_func(*args, **kwargs))
        save_session(session_id, request.session_data)
        response.set_cookie(SESSION_COOKIE_NAME, session_id, max_age=SESSION_TTL, httponly=True, samesite="Lax")
        return response

    return wrapper


def cache_result(ttl=CACHE_TTL, key_prefix="cache"):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = f"{key_prefix}:{func.__name__}:{json.dumps([args, kwargs], sort_keys=True, default=str)}"
            cached = redis_client.get(cache_key)
            if cached is not None:
                try:
                    return json.loads(cached)
                except json.JSONDecodeError:
                    return cached
            result = func(*args, **kwargs)
            try:
                redis_client.set(cache_key, json.dumps(result, default=str), ex=ttl)
            except TypeError:
                redis_client.set(cache_key, str(result), ex=ttl)
            return result

        return wrapper

    return decorator


